const generateData = (limit: number, level: number, prefix: number) => {
  const data: TableData[] = [];
  const levelStack = [];
  while (level) {
    levelStack.push(level);
    level--;
  }
  const levelPrefix = levelStack.join('-');
  for (let i = 1; i <= limit; i++) {
    data.push({
      key: `${prefix}-${levelPrefix}-${i}`,
      name: `John Brown ${levelPrefix}`,
      age: `${i}2`,
      address: `New York No. ${i} Lake Park`,
      description: `My name is John Brown, I am ${i}2 years old, living in New York No. ${i} Lake Park.`,
      column1: `New York No. ${i} Lake Park`,
      column2: `New York No. ${i} Lake Park`,
      column3: `New York No. ${i} Lake Park`,
    });
  }
  return data;
};

// 普通数据
const data = generateData(19, 1, 0);

// 树形数据
const treeData = data.map(item => ({ ...item }));
[2, 4, 5, 7, 8].forEach(i => {
  const firstLevel = generateData(3, 2, i);
  const secondLevel = generateData(1, 3, i);
  firstLevel[1].children = secondLevel;
  treeData[i].children = firstLevel;
});

const expandableConfig = {
  expandedRowRender: (record: TableData) => <p>{record.description}</p>,
};
const titleConfig = () => 'Here is title';
const showHeaderConfig = true;
const footerConfig = () => 'Here is footer';
// const paginationConfig = { position: 'bottom' };

export function AllTable() {
  const [bordered, setBordered] = useState(false);
  const [loading, setLoading] = useState(false);
  // const [pagination, setPagination] = useState(paginationConfig);
  const [size, setSize] = useState('medium' as DefaultSizeType);
  const [expandable, setExpandable] = useState<any>();
  const [title, setTitle] = useState<any>();
  const [showHeader, setShowHeader] = useState(showHeaderConfig);
  const [showMultiHeader, setShowMultiHeader] = useState(false);
  const [footer, setFooter] = useState<any>();
  const [rowSelection, setRowSelection] = useState<any>();
  const [hasData, setHasData] = useState(true);
  const [tableLayout, setTableLayout] = useState(undefined);
  const [top, setTop] = useState('');
  const [bottom, setBottom] = useState('bottomRight');
  const [ellipsis, setEllipsis] = useState(false);
  const [xScroll, setxScroll] = useState('');
  const [yScroll, setyScroll] = useState(false);
  const [dataType, setDataType] = useState('normal');
  const [sticky, setSticky] = useState(false);
  const [checkStrictly, setCheckStrictly] = useState(true);

  const handleSizeChange = (v: any) => {
    setSize(v);
  };

  const handleTableLayoutChange = (e: any) => {
    setTableLayout(e);
  };

  const handleExpandChange = (enable: boolean) => {
    setExpandable(enable ? expandableConfig : null);
  };

  const handleEllipsisChange = (enable: boolean) => {
    setEllipsis(enable);
  };

  const handleTitleChange = (enable: boolean) => {
    setTitle(enable ? () => titleConfig : undefined);
  };

  const handleHeaderChange = (enable: boolean) => {
    setShowHeader(enable);
  };

  const handleFooterChange = (enable: boolean) => {
    setFooter(enable ? () => footerConfig : undefined);
  };

  const handleRowSelectionChange = (e: any) => {
    const type = e;
    setRowSelection(type ? { type } : undefined);
  };

  const handleYScrollChange = (enable: boolean) => {
    setyScroll(enable);
  };

  const handleXScrollChange = (e: any) => {
    setxScroll(e);
  };

  const handleDataChange = (enable: boolean) => {
    setHasData(enable);
  };

  const handlePaginationTop = (e: any) => {
    setTop(e);
  };

  const handlePaginationBottom = (e: any) => {
    setBottom(e);
  };

  const handleDataType = (e: any) => {
    setDataType(e);
  };

  const handleMultiHeaderChange = (enable: boolean) => {
    setShowMultiHeader(enable);
  };

  const handleStickyChange = (enable: boolean) => {
    setSticky(enable);
  };

  const handleCheckStrictlyChange = (enable: boolean) => {
    setCheckStrictly(enable);
  };

  const scroll: { x?: number | string; y?: number | string } = {};
  if (yScroll) {
    scroll.y = 240;
  }
  if (xScroll) {
    scroll.x = '100vw';
  }

  const tableColumns: ColumnsType<TableData> = columns.map(
    item => ({ ...item, ellipsis } as unknown as ColumnType<TableData>),
  );
  if (xScroll === 'fixed') {
    tableColumns[0].fixed = true;
    tableColumns[tableColumns.length - 1].fixed = 'right';
  }

  const multiTableColumns: ColumnsType<TableData> = multiColumns.map(
    item => ({ ...item, ellipsis } as unknown as ColumnType<TableData>),
  );
  if (xScroll === 'fixed') {
    multiTableColumns[0].fixed = true;
    multiTableColumns[multiTableColumns.length - 1].fixed = 'right';
  }

  const state: TableProps<TableData> = {
    columns: showMultiHeader ? multiTableColumns : tableColumns,
    dataSource: hasData ? (dataType === 'tree' ? treeData : data) : [],
    bordered,
    loading,
    showHeader,
    size,
    sticky,
  };

  if (expandable) {
    state.expandable = expandable;
  }
  if (title) {
    state.title = title;
  }
  if (footer) {
    state.footer = footer;
  }
  if (rowSelection) {
    state.rowSelection = rowSelection;
    if (state.rowSelection) {
      state.rowSelection.checkStrictly = checkStrictly;
    }
  }

  function onChange(
    pagination: TablePaginationConfig,
    filters: Record<string, (Key | boolean)[] | null>,
    sorter: SorterResult<TableData> | SorterResult<TableData>[],
    extra: TableCurrentDataSource<TableData>,
  ) {
    console.log('params', pagination, filters, sorter, extra);
  }

  return (
    <>
      <div className="actions">
        <div title="Bordered" className="action-item">
          Bordered: <Switch checked={bordered} onChange={setBordered} />
        </div>
        <div title="loading" className="action-item">
          Loading: <Switch checked={loading} onChange={setLoading} />
        </div>
        <div title="Title" className="action-item">
          Title: <Switch checked={Boolean(title)} onChange={handleTitleChange} />
        </div>
        <div title="Footer" className="action-item">
          Footer: <Switch checked={Boolean(footer)} onChange={handleFooterChange} />
        </div>
        <div title="Column Header" className="action-item">
          Column Header: <Switch checked={Boolean(showHeader)} onChange={handleHeaderChange} />
        </div>
        <div title="Multi Header" className="action-item">
          Multi Header: <Switch checked={Boolean(showMultiHeader)} onChange={handleMultiHeaderChange} />
        </div>
        <div title="Fixed Header" className="action-item">
          Fixed Header: <Switch checked={Boolean(yScroll)} onChange={handleYScrollChange} />
        </div>
        <div title="Sticky Header" className="action-item">
          Sticky Header: <Switch checked={Boolean(sticky)} onChange={handleStickyChange} />
        </div>
        <div title="Expandable" className="action-item">
          Expandable: <Switch checked={Boolean(expandable)} onChange={handleExpandChange} />
        </div>
        <div title="Ellipsis" className="action-item">
          Ellipsis: <Switch checked={Boolean(ellipsis)} onChange={handleEllipsisChange} />
        </div>
        <div title="CheckStrictly" className="action-item">
          CheckStrictly: <Switch checked={Boolean(checkStrictly)} onChange={handleCheckStrictlyChange} />
        </div>
        <div title="Row Selection" className="action-item">
          Row Selection:
          <Radio.Group value={rowSelection ? rowSelection.type : ''} onChange={handleRowSelectionChange}>
            <Radio.Button value="">Unset</Radio.Button>
            <Radio.Button value="radio">Radio</Radio.Button>
            <Radio.Button value="checkbox">Checkbox</Radio.Button>
          </Radio.Group>
        </div>
        <div title="Size" className="action-item">
          Size:
          <Radio.Group value={size} onChange={handleSizeChange}>
            <Radio.Button value="large">Large</Radio.Button>
            <Radio.Button value="medium">Medium</Radio.Button>
            <Radio.Button value="small">Small</Radio.Button>
          </Radio.Group>
        </div>
        <div title="Table Scroll" className="action-item">
          Table Scroll:
          <Radio.Group value={xScroll as any} onChange={handleXScrollChange}>
            <Radio.Button value="">Unset</Radio.Button>
            <Radio.Button value="scroll">Scroll</Radio.Button>
            <Radio.Button value="fixed">Fixed Columns</Radio.Button>
          </Radio.Group>
        </div>
        <div title="Table Layout" className="action-item">
          Table Layout:
          <Radio.Group value={tableLayout} onChange={handleTableLayoutChange}>
            <Radio.Button value="">Unset</Radio.Button>
            <Radio.Button value="fixed">Fixed</Radio.Button>
          </Radio.Group>
        </div>
        <div title="Pagination Top" className="action-item">
          Pagination Top:
          <Radio.Group value={top} onChange={handlePaginationTop}>
            <Radio.Button value="topLeft">TopLeft</Radio.Button>
            <Radio.Button value="topCenter">TopCenter</Radio.Button>
            <Radio.Button value="topRight">TopRight</Radio.Button>
            <Radio.Button value="">None</Radio.Button>
          </Radio.Group>
        </div>
        <div title="Pagination Bottom" className="action-item">
          Pagination Bottom:
          <Radio.Group value={bottom} onChange={handlePaginationBottom}>
            <Radio.Button value="bottomLeft">BottomLeft</Radio.Button>
            <Radio.Button value="bottomCenter">BottomCenter</Radio.Button>
            <Radio.Button value="bottomRight">BottomRight</Radio.Button>
            <Radio.Button value="">None</Radio.Button>
          </Radio.Group>
        </div>
        <div title="Has Data" className="action-item">
          Has Data: <Switch checked={Boolean(hasData)} onChange={handleDataChange} />
        </div>
        <div title="Pagination Bottom" className="action-item">
          Data:
          <Radio.Group value={dataType} onChange={handleDataType}>
            <Radio.Button value="normal">Normal</Radio.Button>
            <Radio.Button value="tree">Tree</Radio.Button>
          </Radio.Group>
        </div>
      </div>
      <Table
        {...state}
        tableLayout={tableLayout}
        scroll={scroll}
        pagination={!top && !bottom ? false : ({ position: [top, bottom] } as TablePaginationConfig)}
        onChange={onChange}
      />
    </>
  );
}

