export const EmptyDemo = () => {
  const [bordered, setBordered] = useState<boolean>();
  const [size, setSize] = useState<DefaultSizeType>('medium');
  const [needColumns, setColumns] = useState<boolean>();
  return (
    <Space direction="vertical" style={{ width: '100%' }}>
      <Space>
        <div>
          <span>边框：</span>
          <Switch checked={bordered} onChange={setBordered} />
        </div>
        <div>
          <span>大小：</span>
          <Radio.Group value={size} onChange={v => setSize(v as DefaultSizeType)}>
            <Radio.Button value="large">大</Radio.Button>
            <Radio.Button value="medium">中</Radio.Button>
            <Radio.Button value="small">小</Radio.Button>
          </Radio.Group>
        </div>
        <div>
          <span>需要列配置：</span>
          <Switch checked={needColumns} onChange={setColumns} />
        </div>
      </Space>
      <Table bordered={bordered} size={size} dataSource={[]} columns={needColumns ? columns3 : []} pagination={false} />
      <Table
        bordered={bordered}
        size={size}
        dataSource={[]}
        columns={needColumns ? columns3 : []}
        pagination={false}
        renderEmpty="没数据了"
      />
      <Table
        bordered={bordered}
        size={size}
        dataSource={[]}
        columns={needColumns ? columns3 : []}
        renderEmpty={
          <Empty image={<EmptyNeutralNoAccess />} title="没有权限访问" description="请登录后尝试访问">
            <Button>返回主页</Button>
            <Button type="primary">申请权限</Button>
          </Empty>
        }
      />
    </Space>
  );
};

export const SortDemo = () => {
  const [ds, setDs] = React.useState<TableData2[]>();
  // const [pageSize, setPageSize] = React.useState<number>(10);
  const onChange = (_p: any, _f: any, s: any, a: TableCurrentDataSource<TableData2>) => {
    console.log(ds);
    if (a.action === TableAction.SORT) {
      console.log('currentDataSource', a.currentDataSource);
      const newData = [];
      for (let i = a.currentDataSource.length + 1; i <= a.currentDataSource.length + 10; i++) {
        newData.push({
          key: `${i}`,
          name: 'Jim Green',
          age: 40,
          address: 'London Park',
        });
      }
      setDs(ds?.concat(newData));
    }
  };

  React.useEffect(() => {
    const s = [];
    for (let i = 1; i <= 100; i++) {
      s.push({
        key: `${i}`,
        name: 'Jim Green',
        age: 40,
        address: 'London Park',
      });
    }
    setDs(s);
  }, []);
  return (
    <Table
      columns={columns1}
      dataSource={ds}
      pagination={{
        defaultPageSize: 5,
        // pageSize,
        pageSizeOptions: ['5', '10', '50'],
        onChange: (page, pageSizeState) => {
          console.log('pagination change', page, pageSizeState);
          // setPageSize(pageSizeState || 10);
        },
      }}
      onChange={onChange}
    />
  );
};

